import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import API from '../../services/api';
import {
  Container,
  Box,
  Typography,
  Button,
  AppBar,
  Toolbar,
  Paper,
  TextField,
  CircularProgress,
  Alert
} from '@mui/material';

function AdminHeader() {
  return (
    <AppBar position="static" color="secondary">
      <Toolbar>
        <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
          AutoTechnix (Admin)
        </Typography>
        <Button color="inherit" component={Link} to="/dashboard">Dashboard</Button>
      </Toolbar>
    </AppBar>
  );
}

export default function JobDetails() {
  const { id } = useParams();
  const [job, setJob] = useState(null);
  const [notes, setNotes] = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    async function fetchJob() {
      try {
        const res = await API.get(`/jobs/${id}`);
        setJob(res.data);
        setNotes(res.data.notes || '');
      } catch (e) {
        console.error(e);
        setError('Failed to load job details.');
      } finally {
        setLoading(false);
      }
    }
    fetchJob();
  }, [id]);

  const handleSaveNotes = async () => {
    try {
      setError('');
      setSuccess('');
      await API.patch(`/jobs/${id}/notes`, { notes });
      setSuccess('Notes saved successfully.');
    } catch (e) {
      console.error(e);
      setError('Failed to save notes.');
    }
  };

  if (loading) {
    return <CircularProgress />;
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>;
  }

  if (!job) {
    return <Alert severity="warning">Job not found.</Alert>;
  }

  return (
    <Box sx={{ flexGrow: 1 }}>
      <AdminHeader />
      <Container sx={{ mt: 4, mb: 4 }}>
        <Typography variant="h4" component="h1" sx={{ mb: 2 }}>
          Job Details ({job._id})
        </Typography>

        <Paper sx={{ p: 2, mb: 3 }}>
          <Typography variant="h6">Customer & Car</Typography>
          <Typography><b>Customer:</b> {job.customer?.name}</Typography>
          <Typography><b>Car:</b> {job.car?.model} ({job.car?.regNo})</Typography>
        </Paper>

        <Paper sx={{ p: 2, mb: 3 }}>
          <Typography variant="h6">Customer Complaint</Typography>
          <Typography>{job.complaint}</Typography>
          {job.audioRecording && (
            <Box mt={1}>
              <a href={`${API.defaults.baseURL}/${job.audioRecording}`} target="_blank" rel="noopener noreferrer">
                Listen to audio complaint
              </a>
            </Box>
          )}
        </Paper>

        <Paper sx={{ p: 2, mb: 3 }}>
          <Typography variant="h6">Mechanic's Notes</Typography>
          <TextField
            fullWidth
            multiline
            rows={4}
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
            variant="outlined"
          />
          <Button variant="contained" onClick={handleSaveNotes} sx={{ mt: 2 }}>
            Save Notes
          </Button>
          {success && <Alert severity="success" sx={{mt: 2}}>{success}</Alert>}
        </Paper>

        {/* Parts usage will be added here */}

      </Container>
    </Box>
  );
}
